const { text, session, userId, phone } = $input.first().json;
const systemPrompt = `You are Jyoti, the front-desk assistant for AstroSharma. Recommend packages: DEEP_CHART_ANALYSIS, MATCHMAKING, or MUHURTHAM. Keep it short. End with: 'Shall I help you book this consultation?'`;
return [{ json: { userId, phone, text, session, llmPayload: { model: 'gemini-1.5-flash', systemPrompt, userMessage: text } } }];

const llmText = $input.first().json.text || '';
const prev = $('Build LLM Prompt').first().json;
const userText = prev.llmPayload?.userMessage?.toLowerCase() || '';
const session = prev.session || {};
const userWantsToBook = ['yes', 'book', 'proceed', 'ok'].some(t => userText.includes(t));
let pkg = session.recommendedPackage;
if (llmText.includes('Deep Chart')) pkg = 'DEEP_CHART_ANALYSIS';
if (llmText.includes('Matchmaking')) pkg = 'MATCHMAKING';
if (llmText.includes('Muhurtham')) pkg = 'MUHURTHAM';
const updatedSession = { ...session, recommendedPackage: pkg, messageCount: (session.messageCount || 0) + 1, state: userWantsToBook ? 'CHECKOUT' : 'TRIAGE', checkoutStep: userWantsToBook ? 'NAME' : null };
const replyText = userWantsToBook ? `Wonderful! Let me get a few details. Could you please share the name?` : llmText;
return [{ json: { userId: prev.userId, phone: prev.phone, text: prev.text, replyText, session: updatedSession } }];
